using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"OS: {System.Runtime.InteropServices.RuntimeInformation.OSDescription}");
Console.WriteLine();

// Setup
var smallAnalyzer = new TextAnalyzer("The quick brown fox jumps over the lazy dog near the river bank");

var rng = new Random(42);
var words = new string[1000];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(2, 12);
    var chars = new char[len];
    for (int j = 0; j < len; j++)
        chars[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(chars);
}
var largeAnalyzer = new TextAnalyzer(string.Join(' ', words));

const int WarmupIterations = 500;
const int BenchmarkIterations = 50_000;

void Bench(string name, Action action)
{
    // Warmup
    for (int i = 0; i < WarmupIterations; i++) action();

    // Collect multiple samples
    const int samples = 5;
    var timings = new double[samples];
    for (int s = 0; s < samples; s++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < BenchmarkIterations; i++) action();
        sw.Stop();
        timings[s] = sw.Elapsed.TotalNanoseconds / BenchmarkIterations;
    }
    Array.Sort(timings);
    double median = timings[samples / 2];
    double min = timings[0];
    double max = timings[samples - 1];
    Console.WriteLine($"  {name,-35} median: {median,10:F2} ns   min: {min,10:F2} ns   max: {max,10:F2} ns");
}

Console.WriteLine("Benchmark Results:");
Console.WriteLine(new string('-', 100));

Bench("AverageWordLength (small)", () => smallAnalyzer.AverageWordLength());
Bench("AverageWordLength (large)", () => largeAnalyzer.AverageWordLength());
Bench("WordLengthHistogram (small)", () => smallAnalyzer.WordLengthHistogram());
Bench("WordLengthHistogram (large)", () => largeAnalyzer.WordLengthHistogram());
Bench("UniqueWordCount (small)", () => smallAnalyzer.UniqueWordCount());
Bench("UniqueWordCount (large)", () => largeAnalyzer.UniqueWordCount());

Console.WriteLine(new string('-', 100));

